from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field
from web3 import Web3
from eth_account.messages import encode_defunct

app = FastAPI(title="Web3 Authentication Service")

class AuthRequest(BaseModel):
    message: str = Field(..., min_length=1)
    signature: str = Field(..., min_length=1)
    expected_address: str | None = None

class AuthResponse(BaseModel):
    authenticated: bool
    address: str
    message: str

def normalize_address(address: str) -> str:
    try:
        return Web3.to_checksum_address(address)
    except Exception as e:
        raise ValueError(f"Invalid Ethereum address: {address}") from e

def recover_address(message: str, signature: str) -> str:
    try:
        encoded_message = encode_defunct(text=message)
        recovered = Web3().eth.account.recover_message(encoded_message, signature=signature)
        return Web3.to_checksum_address(recovered)
    except Exception as e:
        raise ValueError("Invalid signature or message") from e

@app.get("/health")
def health():
    return {"status": "ok"}

@app.post("/auth/verify", response_model=AuthResponse)
def verify_signature(payload: AuthRequest):
    try:
        recovered_address = recover_address(payload.message, payload.signature)
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))

    if payload.expected_address is not None:
        try:
            expected_address = normalize_address(payload.expected_address)
        except ValueError as e:
            raise HTTPException(status_code=400, detail=str(e))

        authenticated = recovered_address == expected_address
        if not authenticated:
            raise HTTPException(status_code=401, detail="Signature does not match expected address")
    else:
        authenticated = True

    return AuthResponse(
        authenticated=authenticated,
        address=recovered_address,
        message=payload.message,
    )